"use strict";const e=require("../utils/request.js");exports.cancelBooking=function(o){return e.put(`/bookings/${o}/cancel`)},exports.createBooking=function(o){return e.post("/bookings",o)},exports.createSharedBooking=function(o){return e.post("/bookings/shared",o)},exports.getBookingDetail=function(o,t={},n={}){return e.get(`/bookings/${o}`,t,n)},exports.getVenueAvailableSlots=function(o,t){return e.get(`/bookings/venues/${o}/slots`,{date:t})};
